import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area, Cell, PieChart, Pie } from 'recharts';
import { TrendingUp, Wallet, CheckCircle2, AlertCircle, Clock, Award } from 'lucide-react';
import { Sale, UserRole, User, CommissionStatus } from '../types';

interface DashboardProps {
  sales: Sale[];
  currentUser: User;
}

const Dashboard: React.FC<DashboardProps> = ({ sales, currentUser }) => {
  const isAdmin = currentUser.role === UserRole.ADMIN;

  const stats = useMemo(() => {
    let relevantSales = sales;
    if (!isAdmin) {
      relevantSales = sales.filter(s => s.splits.some(split => split.brokerId === currentUser.id));
    }

    const totalVGV = relevantSales.reduce((acc, curr) => acc + curr.vgv, 0);

    let totalComm = 0;
    let paidComm = 0;
    let pendingComm = 0;
    let overdueComm = 0;

    relevantSales.forEach(sale => {
      sale.splits.forEach(split => {
        if (isAdmin || split.brokerId === currentUser.id) {
          totalComm += split.calculatedValue;
          if (split.status === CommissionStatus.PAID) paidComm += split.calculatedValue;
          if (split.status === CommissionStatus.PENDING) pendingComm += split.calculatedValue;
          if (split.status === CommissionStatus.OVERDUE) overdueComm += split.calculatedValue;
        }
      });
    });

    const brokerPerfMap: Record<string, { name: string; vgv: number; commissions: number }> = {};
    sales.forEach(s => {
      s.splits.forEach(split => {
        if (!brokerPerfMap[split.brokerId]) {
          brokerPerfMap[split.brokerId] = { name: split.brokerName, vgv: 0, commissions: 0 };
        }
        brokerPerfMap[split.brokerId].commissions += split.calculatedValue;
        // Approximation: attribute proportional VGV to each broker in the split
        brokerPerfMap[split.brokerId].vgv += (s.vgv * (split.percentage / 100));
      });
    });

    return {
      totalVGV,
      totalComm,
      paidComm,
      pendingComm,
      overdueComm,
      brokerPerformance: Object.values(brokerPerfMap).sort((a, b) => b.vgv - a.vgv)
    };
  }, [sales, currentUser, isAdmin]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const chartData = [
    { name: 'Jan', vgv: 400000, comm: 24000 },
    { name: 'Fev', vgv: 300000, comm: 18000 },
    { name: 'Mar', vgv: 600000, comm: 36000 },
    { name: 'Abr', vgv: 800000, comm: 48000 },
    { name: 'Mai', vgv: 500000, comm: 30000 },
    { name: 'Jun', vgv: 900000, comm: 54000 },
    { name: 'Jul', vgv: 1200000, comm: 72000 },
  ];

  const statusData = [
    { name: 'Pago', value: stats.paidComm, color: '#10b981' },
    { name: 'Pendente', value: stats.pendingComm, color: '#3b82f6' },
    { name: 'Atrasado', value: stats.overdueComm, color: '#ef4444' },
  ];

  return (
    <div className="space-y-8">
      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <div className="p-2 bg-blue-50 text-blue-600 rounded-lg">
              <TrendingUp size={24} />
            </div>
            <span className="text-xs font-bold text-emerald-500 bg-emerald-50 px-2 py-1 rounded-full">+12%</span>
          </div>
          <p className="text-sm font-medium text-slate-500 mb-1">{isAdmin ? 'VGV Total' : 'Meu VGV'}</p>
          <p className="text-2xl font-bold text-slate-800">{formatCurrency(stats.totalVGV)}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg">
              <Wallet size={24} />
            </div>
            <span className="text-xs font-bold text-indigo-500 bg-indigo-50 px-2 py-1 rounded-full">+8%</span>
          </div>
          <p className="text-sm font-medium text-slate-500 mb-1">{isAdmin ? 'Total Comissões' : 'Comissões Totais'}</p>
          <p className="text-2xl font-bold text-slate-800">{formatCurrency(stats.totalComm)}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <div className="p-2 bg-emerald-50 text-emerald-600 rounded-lg">
              <CheckCircle2 size={24} />
            </div>
            <span className="text-xs font-medium text-slate-400">Pagas</span>
          </div>
          <p className="text-sm font-medium text-slate-500 mb-1">Comissões Recebidas</p>
          <p className="text-2xl font-bold text-slate-800">{formatCurrency(stats.paidComm)}</p>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <div className="p-2 bg-amber-50 text-amber-600 rounded-lg">
              <Clock size={24} />
            </div>
            <span className="text-xs font-medium text-slate-400">Em Aberto</span>
          </div>
          <p className="text-sm font-medium text-slate-500 mb-1">Pendentes / Atrasadas</p>
          <p className="text-2xl font-bold text-slate-800">{formatCurrency(stats.pendingComm + stats.overdueComm)}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="font-bold text-slate-800 text-lg">Evolução de Vendas e Comissões</h3>
            <select className="bg-slate-50 border-none text-sm text-slate-600 rounded-lg px-3 py-2 outline-none cursor-pointer">
              <option>Últimos 6 meses</option>
              <option>Último ano</option>
            </select>
          </div>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorVgv" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} tickFormatter={(v) => `R$${v/1000}k`} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                  formatter={(value: any) => formatCurrency(value)}
                />
                <Area type="monotone" dataKey="vgv" name="VGV" stroke="#3b82f6" strokeWidth={3} fillOpacity={1} fill="url(#colorVgv)" />
                <Area type="monotone" dataKey="comm" name="Comissões" stroke="#6366f1" strokeWidth={2} fill="transparent" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Status Breakdown */}
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h3 className="font-bold text-slate-800 text-lg mb-8">Distribuição de Status</h3>
          <div className="h-[250px] relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={statusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: any) => formatCurrency(value)} />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
              <span className="text-slate-400 text-xs font-medium">Total</span>
              <span className="text-slate-800 font-bold text-lg">
                {formatCurrency(stats.totalComm)}
              </span>
            </div>
          </div>
          <div className="mt-6 space-y-3">
            {statusData.map((item) => (
              <div key={item.name} className="flex items-center justify-between text-sm">
                <div className="flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: item.color }}></div>
                  <span className="text-slate-600">{item.name}</span>
                </div>
                <span className="font-semibold text-slate-800">{formatCurrency(item.value)}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Admin specific: Broker Performance Ranking */}
      {isAdmin && (
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="font-bold text-slate-800 text-lg flex items-center gap-2">
              <Award className="text-blue-600" size={20} /> Ranking de Corretores (VGV)
            </h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="text-left text-xs font-bold text-slate-400 uppercase tracking-wider border-b border-slate-50">
                  <th className="pb-4 pr-4">Posição</th>
                  <th className="pb-4 px-4">Corretor</th>
                  <th className="pb-4 px-4">VGV Produzido</th>
                  <th className="pb-4 px-4 text-right">Comissões Totais</th>
                  <th className="pb-4 pl-4">Progresso</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {stats.brokerPerformance.map((broker, idx) => (
                  <tr key={broker.name} className="group hover:bg-slate-50 transition-colors">
                    <td className="py-4 pr-4 font-bold text-slate-400">#0{idx + 1}</td>
                    <td className="py-4 px-4">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-medium">
                          {broker.name.charAt(0)}
                        </div>
                        <span className="font-semibold text-slate-700">{broker.name}</span>
                      </div>
                    </td>
                    <td className="py-4 px-4 text-slate-600 font-medium">{formatCurrency(broker.vgv)}</td>
                    <td className="py-4 px-4 text-right font-bold text-blue-600">{formatCurrency(broker.commissions)}</td>
                    <td className="py-4 pl-4 min-w-[120px]">
                      <div className="w-full h-2 bg-slate-100 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-blue-500 rounded-full" 
                          style={{ width: `${Math.min(100, (broker.vgv / stats.totalVGV) * 100 * 2.5)}%` }}
                        ></div>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Plus, Search, Calendar, MapPin, DollarSign, Split, Info, Trash2, CheckCircle } from 'lucide-react';
import { Sale, User, UserRole, CommissionStatus, BrokerSplit } from '../types';
import { MOCK_USERS } from '../constants';

interface SalesProps {
  sales: Sale[];
  setSales: React.Dispatch<React.SetStateAction<Sale[]>>;
  currentUser: User;
}

const Sales: React.FC<SalesProps> = ({ sales, setSales, currentUser }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // New Sale Form State
  const [newSale, setNewSale] = useState<Partial<Sale>>({
    saleDate: new Date().toISOString().split('T')[0],
    commissionPercentage: 6,
    splits: []
  });

  const [currentSplit, setCurrentSplit] = useState<{ brokerId: string; percentage: number }>({
    brokerId: '',
    percentage: 100
  });

  const handleAddSplit = () => {
    if (!currentSplit.brokerId) return;
    const broker = MOCK_USERS.find(u => u.id === currentSplit.brokerId);
    if (!broker) return;

    const vgv = Number(newSale.vgv) || 0;
    const totalComm = (vgv * (Number(newSale.commissionPercentage) || 0)) / 100;
    const splitValue = (totalComm * currentSplit.percentage) / 100;

    const newSplit: BrokerSplit = {
      brokerId: broker.id,
      brokerName: broker.name,
      percentage: currentSplit.percentage,
      calculatedValue: splitValue,
      status: CommissionStatus.PENDING
    };

    setNewSale(prev => ({
      ...prev,
      splits: [...(prev.splits || []), newSplit]
    }));
    setCurrentSplit({ brokerId: '', percentage: 0 });
  };

  const handleSaveSale = () => {
    const vgv = Number(newSale.vgv) || 0;
    const commPerc = Number(newSale.commissionPercentage) || 0;
    const totalComm = (vgv * commPerc) / 100;

    const saleToAdd: Sale = {
      id: `s-${Date.now()}`,
      agencyId: currentUser.agencyId,
      saleDate: newSale.saleDate || '',
      propertyAddress: newSale.propertyAddress || '',
      buyerName: newSale.buyerName || '',
      sellerName: newSale.sellerName || '',
      vgv,
      commissionPercentage: commPerc,
      totalCommissionValue: totalComm,
      invoiceIssued: newSale.invoiceIssued || false,
      notes: newSale.notes,
      splits: newSale.splits || []
    };

    setSales(prev => [saleToAdd, ...prev]);
    setIsModalOpen(false);
    setNewSale({ saleDate: new Date().toISOString().split('T')[0], commissionPercentage: 6, splits: [] });
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const filteredSales = sales.filter(s => 
    s.propertyAddress.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.buyerName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
