import React, { useState, useMemo } from 'react';
import { Search, Filter, Download, ArrowUpRight, DollarSign, Clock, CheckCircle2, AlertTriangle } from 'lucide-react';
import { Sale, User, UserRole, CommissionStatus } from '../types';

interface CommissionsProps {
  sales: Sale[];
  currentUser: User;
  onUpdateStatus: (saleId: string, brokerId: string, newStatus: CommissionStatus) => void;
}

const Commissions: React.FC<CommissionsProps> = ({ sales, currentUser, onUpdateStatus }) => {
  const [statusFilter, setStatusFilter] = useState<string>('ALL');
  const [searchTerm, setSearchTerm] = useState('');

  const isAdmin = currentUser.role === UserRole.ADMIN;

  const commissionList = useMemo(() => {
    const list: any[] = [];
    sales.forEach(sale => {
      sale.splits.forEach(split => {
        if (isAdmin || split.brokerId === currentUser.id) {
          list.push({
            saleId: sale.id,
            brokerId: split.brokerId,
            brokerName: split.brokerName,
            property: sale.propertyAddress,
            value: split.calculatedValue,
            status: split.status,
            date: sale.saleDate,
            paymentDate: split.paymentDate,
            paymentMethod: split.paymentMethod
          });
        }
      });
    });
    return list.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [sales, currentUser, isAdmin]);

  const filteredCommissions = commissionList.filter(c => {
    const matchesStatus = statusFilter === 'ALL' || c.status === statusFilter;
    const matchesSearch = c.property.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         c.brokerName.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const getStatusBadge = (status: CommissionStatus) => {
    switch (status) {
      case CommissionStatus.PAID:
        return <span className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-emerald-100"><CheckCircle2 size={14} /> PAGO</span>;
      case CommissionStatus.PENDING:
        return <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-blue-100"><Clock size={14} /> PENDENTE</span>;
      case CommissionStatus.OVERDUE:
        return <span className="bg-red-50 text-red-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-red-100"><AlertTriangle size={14} /> ATRASADO</span>;
    }
  };

  const handleExportCSV = () => {
    const headers = ["Data", "Imóvel", "Corretor", "Valor", "Status"];
    const rows = filteredCommissions.map(c => [
      c.date,
      c.property,
      c.brokerName,
      c.value.toString(),
      c.status
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `comissoes_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      {/* Filters Bar */}
      <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:flex-none">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder="Buscar comissão..." 
              className="pl-9 pr-4 py-2 text-sm bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-100 w-full"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="px-4 py-2 text-sm bg-slate-50 border border-slate-200 rounded-xl outline-none cursor-pointer hover:bg-slate-100 transition-colors"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="ALL">Todos os Status</option>
            <option value={CommissionStatus.PAID}>Pagos</option>
            <option value={CommissionStatus.PENDING}>Pendentes</option>
            <option value={CommissionStatus.OVERDUE}>Atrasados</option>
          </select>
          {isAdmin && (
            <button className="flex items-center gap-2 px-4 py-2 text-sm bg-slate-50 text-slate-600 font-medium rounded-xl hover:bg-slate-100 transition-colors">
              <Filter size={16} /> Filtros Avançados
            </button>
          )}
        </div>
        <button 
          onClick={handleExportCSV}
          className="flex items-center gap-2 px-6 py-2.5 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-lg shadow-slate-200 w-full md:w-auto justify-center"
        >
          <Download size={18} /> Exportar CSV
        </button>
      </div>

      {/* Commission Table */}
      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 text-xs font-bold text-slate-500 uppercase tracking-wider border-b border-slate-100">
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Venda / Imóvel</th>
                <th className="px-6 py-4">Corretor</th>
                <th className="px-6 py-4">Valor Devido</th>
                <th className="px-6 py-4">Data Pagto</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredCommissions.map((comm, idx) => (
                <tr key={`${comm.saleId}-${comm.brokerId}-${idx}`} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">{getStatusBadge(comm.status)}</td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-sm font-semibold text-slate-800">{comm.property}</span>
                      <span className="text-[10px] text-slate-400 uppercase tracking-tight font-medium">Ref: {comm.saleId} • {new Date(comm.date).toLocaleDateString('pt-BR')}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2 text-sm font-medium text-slate-700">
                      <div className="w-6 h-6 rounded-full bg-blue-50 flex items-center justify-center text-[10px] text-blue-600 font-bold">
                        {comm.brokerName.charAt(0)}
                      </div>
                      {comm.brokerName}
                    </div>
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-800">{formatCurrency(comm.value)}</td>
                  <td className="px-6 py-4">
                    {comm.paymentDate ? (
                      <div className="flex flex-col">
                        <span className="text-sm text-slate-700">{new Date(comm.paymentDate).toLocaleDateString('pt-BR')}</span>
                        <span className="text-[10px] text-emerald-500 font-bold uppercase">{comm.paymentMethod}</span>
                      </div>
                    ) : (
                      <span className="text-sm text-slate-400">---</span>
                    )}
                  </td>
                  <td className="px-6 py-4 text-right">
                    {isAdmin && comm.status !== CommissionStatus.PAID ? (
                      <button 
                        onClick={() => onUpdateStatus(comm.saleId, comm.brokerId, CommissionStatus.PAID)}
                        className="p-2 text-emerald-500 hover:bg-emerald-50 rounded-lg transition-colors group relative"
                        title="Marcar como Pago"
                      >
                        <DollarSign size={18} />
                      </button>
                    ) : (
                      <button className="p-2 text-slate-300 cursor-not-allowed">
                        <ArrowUpRight size={18} />
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredCommissions.length === 0 && (
            <div className="p-16 text-center">
              <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
                <Wallet className="text-slate-200" size={40} />
              </div>
              <h3 className="text-lg font-bold text-slate-800 mb-2">Nenhuma comissão aqui</h3>
              <p className="text-slate-500 max-w-sm mx-auto">Ajuste os filtros ou verifique se as vendas registradas possuem corretores vinculados.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Commissions;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Sales from './components/Sales';
import Commissions from './components/Commissions';
import { User, Sale, UserRole, CommissionStatus } from './types';
import { MOCK_USERS, MOCK_SALES } from './constants';
import { LogIn, Key, HelpCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState('dashboard');
  const [sales, setSales] = useState<Sale[]>(MOCK_SALES);

  // Persistence simulation (optional enhancement for demo)
  useEffect(() => {
    const saved = localStorage.getItem('comissone_sales');
    if (saved) setSales(JSON.parse(saved));
  }, []);

  useEffect(() => {
    localStorage.setItem('comissone_sales', JSON.stringify(sales));
  }, [sales]);

  const handleUpdateCommissionStatus = (saleId: string, brokerId: string, newStatus: CommissionStatus) => {
    setSales(prevSales => prevSales.map(sale => {
      if (sale.id === saleId) {
        return {
          ...sale,
          splits: sale.splits.map(split => {
            if (split.brokerId === brokerId) {
              return {
                ...split,
                status: newStatus,
                paymentDate: newStatus === CommissionStatus.PAID ? new Date().toISOString().split('T')[0] : undefined,
                paymentMethod: newStatus === CommissionStatus.PAID ? 'PIX' : undefined
              };
            }
            return split;
          })
        };
      }
      return sale;
    }));
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch (activeView) {
      case 'dashboard':
        return <Dashboard sales={sales} currentUser={currentUser} />;
      case 'sales':
        return <Sales sales={sales} setSales={setSales} currentUser={currentUser} />;
      case 'commissions':
        return <Commissions sales={sales} currentUser={currentUser} onUpdateStatus={handleUpdateCommissionStatus} />;
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-center p-8 bg-white rounded-3xl border border-slate-100 shadow-sm">
            <div className="bg-blue-50 p-4 rounded-full mb-6">
              <HelpCircle size={48} className="text-blue-600" />
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Relatórios Customizados</h2>
            <p className="text-slate-500 max-w-md">O módulo de relatórios avançados está sendo preparado para integração com BI. Em breve você terá acesso a KPIs de performance e forecast de faturamento.</p>
          </div>
        );
      case 'team':
        return (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {MOCK_USERS.map(user => (
              <div key={user.id} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4">
                <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-bold text-lg">
                  {user.name.charAt(0)}
                </div>
                <div>
                  <h4 className="font-bold text-slate-800">{user.name}</h4>
                  <p className="text-xs text-slate-400 mb-2">{user.email}</p>
                  <span className={`text-[10px] px-2 py-0.5 rounded font-bold uppercase ${user.role === UserRole.ADMIN ? 'bg-indigo-50 text-indigo-600' : 'bg-emerald-50 text-emerald-600'}`}>
                    {user.role}
                  </span>
                </div>
              </div>
            ))}
          </div>
        );
      default:
        return <Dashboard sales={sales} currentUser={currentUser} />;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
        <div className="w-full max-w-md">
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center p-3 bg-blue-600 rounded-2xl shadow-xl shadow-blue-200 mb-6">
              <LogIn className="text-white" size={32} />
            </div>
            <h1 className="text-3xl font-extrabold text-slate-800">ComissOne</h1>
            <p className="text-slate-500 mt-2">Gestão de Inteligência em Comissões</p>
          </div>

          <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-2xl shadow-slate-200/60">
            <div className="space-y-6">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <Key size={20} className="text-blue-500" /> Escolha seu Perfil
              </h2>
              <div className="grid grid-cols-1 gap-4">
                {MOCK_USERS.map((user) => (
                  <button
                    key={user.id}
                    onClick={() => setCurrentUser(user)}
                    className="w-full group flex items-center justify-between p-5 bg-slate-50 border border-slate-100 rounded-2xl hover:border-blue-400 hover:bg-white hover:shadow-lg transition-all text-left"
                  >
                    <div>
                      <p className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors">{user.name}</p>
                      <p className="text-xs text-slate-400 font-medium uppercase tracking-wider">{user.role}</p>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 group-hover:bg-blue-600 group-hover:border-blue-600 transition-all">
                      <LogIn size={18} className="text-slate-400 group-hover:text-white transition-colors" />
                    </div>
                  </button>
                ))}
              </div>
              <div className="pt-6 border-t border-slate-100">
                <p className="text-xs text-center text-slate-400">
                  Ambiente de demonstração multi-tenant.<br/>
                  Dados isolados por agência.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentUser={currentUser} 
      activeView={activeView} 
      setActiveView={setActiveView}
      onLogout={() => {
        setCurrentUser(null);
        setActiveView('dashboard');
      }}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
