import React, { useState } from 'react';
/* Added ShoppingCart to the imports from lucide-react */
import { Plus, Search, Calendar, MapPin, DollarSign, Split, Info, Trash2, CheckCircle, ShoppingCart } from 'lucide-react';
import { Sale, User, UserRole, CommissionStatus, BrokerSplit } from '../types';
import { MOCK_USERS } from '../constants';

interface SalesProps {
  sales: Sale[];
  setSales: React.Dispatch<React.SetStateAction<Sale[]>>;
  currentUser: User;
}

const Sales: React.FC<SalesProps> = ({ sales, setSales, currentUser }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // New Sale Form State
  const [newSale, setNewSale] = useState<Partial<Sale>>({
    saleDate: new Date().toISOString().split('T')[0],
    commissionPercentage: 6,
    splits: []
  });

  const [currentSplit, setCurrentSplit] = useState<{ brokerId: string; percentage: number }>({
    brokerId: '',
    percentage: 100
  });

  const handleAddSplit = () => {
    if (!currentSplit.brokerId) return;
    const broker = MOCK_USERS.find(u => u.id === currentSplit.brokerId);
    if (!broker) return;

    const vgv = Number(newSale.vgv) || 0;
    const totalComm = (vgv * (Number(newSale.commissionPercentage) || 0)) / 100;
    const splitValue = (totalComm * currentSplit.percentage) / 100;

    const newSplit: BrokerSplit = {
      brokerId: broker.id,
      brokerName: broker.name,
      percentage: currentSplit.percentage,
      calculatedValue: splitValue,
      status: CommissionStatus.PENDING
    };

    setNewSale(prev => ({
      ...prev,
      splits: [...(prev.splits || []), newSplit]
    }));
    setCurrentSplit({ brokerId: '', percentage: 0 });
  };

  const handleSaveSale = () => {
    const vgv = Number(newSale.vgv) || 0;
    const commPerc = Number(newSale.commissionPercentage) || 0;
    const totalComm = (vgv * commPerc) / 100;

    const saleToAdd: Sale = {
      id: `s-${Date.now()}`,
      agencyId: currentUser.agencyId,
      saleDate: newSale.saleDate || '',
      propertyAddress: newSale.propertyAddress || '',
      buyerName: newSale.buyerName || '',
      sellerName: newSale.sellerName || '',
      vgv,
      commissionPercentage: commPerc,
      totalCommissionValue: totalComm,
      invoiceIssued: newSale.invoiceIssued || false,
      notes: newSale.notes,
      splits: newSale.splits || []
    };

    setSales(prev => [saleToAdd, ...prev]);
    setIsModalOpen(false);
    setNewSale({ saleDate: new Date().toISOString().split('T')[0], commissionPercentage: 6, splits: [] });
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const filteredSales = sales.filter(s => 
    s.propertyAddress.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.buyerName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por imóvel ou comprador..." 
            className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-100 focus:border-blue-400 outline-none transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-semibold transition-all shadow-lg shadow-blue-200"
        >
          <Plus size={20} /> Nova Venda
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 text-xs font-bold text-slate-500 uppercase tracking-wider border-b border-slate-100">
                <th className="px-6 py-4">Data</th>
                <th className="px-6 py-4">Imóvel</th>
                <th className="px-6 py-4">VGV</th>
                <th className="px-6 py-4">Comissão (Total)</th>
                <th className="px-6 py-4">Status NF</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredSales.map(sale => (
                <tr key={sale.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2 text-slate-600">
                      <Calendar size={14} />
                      <span className="text-sm font-medium">{new Date(sale.saleDate).toLocaleDateString('pt-BR')}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <MapPin size={14} className="text-slate-400 shrink-0" />
                      <div className="flex flex-col">
                        <span className="text-sm font-semibold text-slate-800 line-clamp-1">{sale.propertyAddress}</span>
                        <span className="text-xs text-slate-400 italic">Comprador: {sale.buyerName}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-700">{formatCurrency(sale.vgv)}</td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-sm font-bold text-blue-600">{formatCurrency(sale.totalCommissionValue)}</span>
                      <span className="text-[10px] text-slate-400">{sale.commissionPercentage}% de comissão</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    {sale.invoiceIssued ? (
                      <span className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-emerald-50 text-emerald-700 text-[11px] font-bold rounded-full uppercase">
                        <CheckCircle size={12} /> Emitida
                      </span>
                    ) : (
                      <span className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-amber-50 text-amber-700 text-[11px] font-bold rounded-full uppercase">
                        Pendente
                      </span>
                    )}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button className="p-2 hover:bg-blue-50 text-slate-400 hover:text-blue-600 rounded-lg transition-colors">
                      <Info size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredSales.length === 0 && (
            <div className="p-12 text-center">
              <div className="bg-slate-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                <ShoppingCart className="text-slate-300" size={32} />
              </div>
              <p className="text-slate-500 font-medium">Nenhuma venda encontrada</p>
            </div>
          )}
        </div>
      </div>

      {/* New Sale Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-white sticky top-0 z-10">
              <div>
                <h3 className="text-xl font-bold text-slate-800">Registrar Nova Venda</h3>
                <p className="text-sm text-slate-500">Insira os detalhes do imóvel e divisões de comissão.</p>
              </div>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 p-2">&times;</button>
            </div>

            <div className="flex-1 overflow-y-auto p-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Sale Details */}
                <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Imóvel (Endereço)</label>
                    <input 
                      type="text" 
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-100 outline-none"
                      placeholder="Ex: Av. Atlântica, 100"
                      onChange={(e) => setNewSale({...newSale, propertyAddress: e.target.value})}
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">VGV (Valor Venda)</label>
                      <input 
                        type="number" 
                        className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-100 outline-none"
                        placeholder="R$ 0,00"
                        onChange={(e) => setNewSale({...newSale, vgv: Number(e.target.value)})}
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">% Comissão</label>
                      <input 
                        type="number" 
                        className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-100 outline-none"
                        defaultValue={6}
                        onChange={(e) => setNewSale({...newSale, commissionPercentage: Number(e.target.value)})}
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Comprador</label>
                      <input 
                        type="text" 
                        className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-100 outline-none"
                        onChange={(e) => setNewSale({...newSale, buyerName: e.target.value})}
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-xs font-bold text-slate-500 uppercase">Vendedor</label>
                      <input 
                        type="text" 
                        className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-100 outline-none"
                        onChange={(e) => setNewSale({...newSale, sellerName: e.target.value})}
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Notas Adicionais</label>
                    <textarea 
                      className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-100 outline-none min-h-[100px]"
                      onChange={(e) => setNewSale({...newSale, notes: e.target.value})}
                    />
                  </div>
                </div>

                {/* Split Configuration */}
                <div className="space-y-6">
                  <div className="bg-blue-50/50 p-6 rounded-2xl border border-blue-100">
                    <h4 className="font-bold text-blue-800 flex items-center gap-2 mb-4">
                      <Split size={18} /> Divisão de Comissões
                    </h4>

                    <div className="grid grid-cols-2 gap-3 mb-4">
                      <select 
                        className="px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm"
                        value={currentSplit.brokerId}
                        onChange={(e) => setCurrentSplit({...currentSplit, brokerId: e.target.value})}
                      >
                        <option value="">Selecionar Corretor</option>
                        {MOCK_USERS.filter(u => u.role === UserRole.BROKER).map(u => (
                          <option key={u.id} value={u.id}>{u.name}</option>
                        ))}
                      </select>
                      <div className="flex gap-2">
                        <input 
                          type="number" 
                          className="w-full px-3 py-2.5 bg-white border border-slate-200 rounded-xl text-sm" 
                          placeholder="%"
                          value={currentSplit.percentage}
                          onChange={(e) => setCurrentSplit({...currentSplit, percentage: Number(e.target.value)})}
                        />
                        <button 
                          onClick={handleAddSplit}
                          className="bg-blue-600 text-white p-2.5 rounded-xl hover:bg-blue-700 transition-colors"
                        >
                          <Plus size={20} />
                        </button>
                      </div>
                    </div>

                    <div className="space-y-3">
                      {(newSale.splits || []).map((split, idx) => (
                        <div key={idx} className="bg-white p-3 rounded-xl border border-blue-100 flex items-center justify-between">
                          <div>
                            <p className="text-sm font-bold text-slate-800">{split.brokerName}</p>
                            <p className="text-[10px] text-slate-400 font-medium uppercase">{split.percentage}% - {formatCurrency(split.calculatedValue)}</p>
                          </div>
                          <button 
                            className="text-red-400 hover:text-red-600 transition-colors"
                            onClick={() => setNewSale({...newSale, splits: newSale.splits?.filter((_, i) => i !== idx)})}
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      ))}
                      {(newSale.splits || []).length === 0 && (
                        <p className="text-center text-xs text-slate-400 italic py-4">Adicione corretores para dividir a comissão</p>
                      )}
                    </div>
                  </div>

                  <div className="flex items-center gap-2 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                    <input 
                      type="checkbox" 
                      id="invoice" 
                      className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500" 
                      onChange={(e) => setNewSale({...newSale, invoiceIssued: e.target.checked})}
                    />
                    <label htmlFor="invoice" className="text-sm font-medium text-slate-700">A Nota Fiscal (NF) já foi emitida?</label>
                  </div>
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 bg-slate-50 flex justify-end gap-3 sticky bottom-0">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-6 py-2.5 text-slate-600 font-semibold hover:bg-slate-100 rounded-xl transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveSale}
                className="px-8 py-2.5 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg shadow-blue-200 transition-all"
              >
                Salvar Venda
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sales;

import React, { useState, useMemo } from 'react';
/* Added Wallet to the imports from lucide-react */
import { Search, Filter, Download, ArrowUpRight, DollarSign, Clock, CheckCircle2, AlertTriangle, Wallet } from 'lucide-react';
import { Sale, User, UserRole, CommissionStatus } from '../types';

interface CommissionsProps {
  sales: Sale[];
  currentUser: User;
  onUpdateStatus: (saleId: string, brokerId: string, newStatus: CommissionStatus) => void;
}

const Commissions: React.FC<CommissionsProps> = ({ sales, currentUser, onUpdateStatus }) => {
  const [statusFilter, setStatusFilter] = useState<string>('ALL');
  const [searchTerm, setSearchTerm] = useState('');

  const isAdmin = currentUser.role === UserRole.ADMIN;

  const commissionList = useMemo(() => {
    const list: any[] = [];
    sales.forEach(sale => {
      sale.splits.forEach(split => {
        if (isAdmin || split.brokerId === currentUser.id) {
          list.push({
            saleId: sale.id,
            brokerId: split.brokerId,
            brokerName: split.brokerName,
            property: sale.propertyAddress,
            value: split.calculatedValue,
            status: split.status,
            date: sale.saleDate,
            paymentDate: split.paymentDate,
            paymentMethod: split.paymentMethod
          });
        }
      });
    });
    return list.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [sales, currentUser, isAdmin]);

  const filteredCommissions = commissionList.filter(c => {
    const matchesStatus = statusFilter === 'ALL' || c.status === statusFilter;
    const matchesSearch = c.property.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         c.brokerName.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const getStatusBadge = (status: CommissionStatus) => {
    switch (status) {
      case CommissionStatus.PAID:
        return <span className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-emerald-100"><CheckCircle2 size={14} /> PAGO</span>;
      case CommissionStatus.PENDING:
        return <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-blue-100"><Clock size={14} /> PENDENTE</span>;
      case CommissionStatus.OVERDUE:
        return <span className="bg-red-50 text-red-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-red-100"><AlertTriangle size={14} /> ATRASADO</span>;
    }
  };

  const handleExportCSV = () => {
    const headers = ["Data", "Imóvel", "Corretor", "Valor", "Status"];
    const rows = filteredCommissions.map(c => [
      c.date,
      c.property,
      c.brokerName,
      c.value.toString(),
      c.status
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `comissoes_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      {/* Filters Bar */}
      <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="flex flex-wrap items-center gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:flex-none">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input 
              type="text" 
              placeholder="Buscar comissão..." 
              className="pl-9 pr-4 py-2 text-sm bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-100 w-full"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="px-4 py-2 text-sm bg-slate-50 border border-slate-200 rounded-xl outline-none cursor-pointer hover:bg-slate-100 transition-colors"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="ALL">Todos os Status</option>
            <option value={CommissionStatus.PAID}>Pagos</option>
            <option value={CommissionStatus.PENDING}>Pendentes</option>
            <option value={CommissionStatus.OVERDUE}>Atrasados</option>
          </select>
          {isAdmin && (
            <button className="flex items-center gap-2 px-4 py-2 text-sm bg-slate-50 text-slate-600 font-medium rounded-xl hover:bg-slate-100 transition-colors">
              <Filter size={16} /> Filtros Avançados
            </button>
          )}
        </div>
        <button 
          onClick={handleExportCSV}
          className="flex items-center gap-2 px-6 py-2.5 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-lg shadow-slate-200 w-full md:w-auto justify-center"
        >
          <Download size={18} /> Exportar CSV
        </button>
      </div>

      {/* Commission Table */}
      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 text-xs font-bold text-slate-500 uppercase tracking-wider border-b border-slate-100">
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4">Venda / Imóvel</th>
                <th className="px-6 py-4">Corretor</th>
                <th className="px-6 py-4">Valor Devido</th>
                <th className="px-6 py-4">Data Pagto</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredCommissions.map((comm, idx) => (
                <tr key={`${comm.saleId}-${comm.brokerId}-${idx}`} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">{getStatusBadge(comm.status)}</td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-sm font-semibold text-slate-800">{comm.property}</span>
                      <span className="text-[10px] text-slate-400 uppercase tracking-tight font-medium">Ref: {comm.saleId} • {new Date(comm.date).toLocaleDateString('pt-BR')}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2 text-sm font-medium text-slate-700">
                      <div className="w-6 h-6 rounded-full bg-blue-50 flex items-center justify-center text-[10px] text-blue-600 font-bold">
                        {comm.brokerName.charAt(0)}
                      </div>
                      {comm.brokerName}
                    </div>
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-800">{formatCurrency(comm.value)}</td>
                  <td className="px-6 py-4">
                    {comm.paymentDate ? (
                      <div className="flex flex-col">
