        </div>

        <button 
          onClick={() => setIsModalOpen(true)}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-10 py-3.5 rounded-2xl font-bold transition-all shadow-xl shadow-blue-300/50"
        >
          <Plus size={20} /> Nova Venda
        </button>
      </div>

      {/* Sales Table - Réplica fiel do Screenshot */}
      <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-white text-[12px] font-bold text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                <th className="px-12 py-8">DATA</th>
                <th className="px-12 py-8">IMÓVEL</th>
