                      <input type="text" value={newSale.sellerName || ''} placeholder="Nome do Vendedor" className="w-full px-5 py-3 bg-slate-50 border-none rounded-2xl text-sm" onChange={e => setNewSale({...newSale, sellerName: e.target.value})} />
                    </div>
                  </div>

                  <div className="flex items-center gap-3 p-4 bg-blue-50/30 rounded-2xl border border-blue-50">
                    <div className={`w-10 h-6 rounded-full relative transition-colors cursor-pointer ${newSale.invoiceIssued ? 'bg-blue-600' : 'bg-slate-200'}`} onClick={() => setNewSale({...newSale, invoiceIssued: !newSale.invoiceIssued})}>
                      <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${newSale.invoiceIssued ? 'left-5' : 'left-1'}`} />
                    </div>
                    <span className="text-xs font-bold text-slate-600">NF já emitida?</span>
                  </div>
                </div>

                <div className="bg-slate-50/50 p-8 rounded-[32px] border border-slate-100 space-y-6">
                  <div className="flex items-center gap-2 mb-2">
                    <Split className="text-blue-500" size={20} />
                    <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest">Rateio de Comissão</h4>
                  </div>

                  <div className="flex gap-2">
                    <select 
                      className="flex-1 px-4 py-3 bg-white border border-slate-100 rounded-xl text-xs font-semibold outline-none focus:ring-2 focus:ring-blue-100"
                      value={currentSplit.brokerId}
                      onChange={e => setCurrentSplit({...currentSplit, brokerId: e.target.value})}
                    >
                      <option value="">Selecionar Corretor</option>
                      {MOCK_USERS.filter(u => u.role === UserRole.BROKER).map(u => (
                        <option key={u.id} value={u.id}>{u.name}</option>
                      ))}
                    </select>
                    <input 
                      type="number" 
                      className="w-24 px-4 py-3 bg-white border border-slate-100 rounded-xl text-xs font-bold text-center outline-none focus:ring-2 focus:ring-blue-100"
                      value={currentSplit.percentage}
                      onChange={e => setCurrentSplit({...currentSplit, percentage: Number(e.target.value)})}
                      placeholder="%"
                    />
                    <button 
                      onClick={handleAddSplit}
