              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveSale}
                className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-3 rounded-2xl font-black transition-all shadow-xl shadow-blue-200"
              >
                {editingSale ? 'Salvar Alterações' : 'Salvar Venda'}
