                      </div>
                    )}
                  </div>
                </div>

                <div className="bg-slate-50/50 p-8 rounded-[32px] border border-slate-100 space-y-6">
                  <div className="flex items-center gap-2 mb-2">
                    <Split className="text-blue-500" size={20} />
                    <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest">Rateio de Comissão</h4>
                  </div>

                  <div className="flex gap-2">
                    <select 
                      className="flex-1 px-4 py-3 bg-white border border-slate-100 rounded-xl text-xs font-semibold outline-none focus:ring-2 focus:ring-blue-100"
                      value={currentSplit.brokerId}
                      onChange={e => setCurrentSplit({...currentSplit, brokerId: e.target.value})}
                    >
                      <option value="">Selecionar Corretor</option>
                      {MOCK_USERS.filter(u => u.role === UserRole.BROKER).map(u => (
                        <option key={u.id} value={u.id}>{u.name}</option>
                      ))}
                    </select>
                    <input 
                      type="number" 
                      className="w-24 px-4 py-3 bg-white border border-slate-100 rounded-xl text-xs font-bold text-center outline-none focus:ring-2 focus:ring-blue-100"
                      value={currentSplit.percentage}
                      onChange={e => setCurrentSplit({...currentSplit, percentage: Number(e.target.value)})}
                      placeholder="%"
                    />
                    <button 
                      onClick={handleAddSplit}
                      className="bg-blue-600 text-white p-3 rounded-xl hover:bg-blue-700 transition-colors shadow-lg shadow-blue-100"
                    >
                      <Plus size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 max-h-[250px] overflow-y-auto pr-2">
                    {(newSale.splits || []).map((split, idx) => (
                      <div key={idx} className="bg-white p-4 rounded-2xl flex items-center justify-between border border-slate-100 animate-in slide-in-from-bottom-2 duration-300">
                        <div>
                          <p className="text-xs font-black text-slate-800">{split.brokerName}</p>
                          <p className="text-[10px] text-blue-600 font-bold uppercase">{split.percentage}% — {formatCurrency(split.calculatedValue)}</p>
                        </div>
                        <button 
                          onClick={() => setNewSale({...newSale, splits: newSale.splits?.filter((_, i) => i !== idx)})}
                          className="text-slate-300 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    ))}
                  </div>

                  <div className="pt-6 border-t border-slate-100 space-y-2">
                     <div className="flex justify-between text-[10px] font-black uppercase text-slate-400">
                        <span>Soma do Rateio</span>
                        <span className={(newSale.splits?.reduce((a,b)=>a+b.percentage, 0) || 0) === 100 ? 'text-emerald-500' : 'text-amber-500'}>
                          {(newSale.splits?.reduce((a,b)=>a+b.percentage, 0) || 0)}%
                        </span>
                     </div>
                  </div>
                </div>
              </div>
            </div>

            <div className="p-8 border-t border-slate-50 bg-slate-50/50 flex justify-end gap-4 sticky bottom-0 z-10">
              <button 
                onClick={closeModal}
                className="px-8 py-3 text-slate-400 font-bold hover:text-slate-600 transition-colors"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveSale}
                className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-3 rounded-2xl font-black transition-all shadow-xl shadow-blue-200"
              >
                {editingSale ? 'Salvar Alterações' : 'Salvar Venda'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sales;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Sales from './components/Sales';
import Commissions from './components/Commissions';
import Team from './components/Team';
import { User, Sale, UserRole, CommissionStatus } from './types';
import { MOCK_USERS, MOCK_SALES } from './constants';
import { LogIn, Key, HelpCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState('dashboard');
  const [sales, setSales] = useState<Sale[]>(MOCK_SALES);
  const [team, setTeam] = useState<User[]>(MOCK_USERS);

  // Persistence simulation
  useEffect(() => {
    const savedSales = localStorage.getItem('comissone_sales');
    if (savedSales) setSales(JSON.parse(savedSales));

    const savedTeam = localStorage.getItem('comissone_team');
    if (savedTeam) setTeam(JSON.parse(savedTeam));
  }, []);

  useEffect(() => {
    localStorage.setItem('comissone_sales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('comissone_team', JSON.stringify(team));
  }, [team]);

  const handleUpdateCommissionStatus = (saleId: string, brokerId: string, newStatus: CommissionStatus) => {
    setSales(prevSales => prevSales.map(sale => {
      if (sale.id === saleId) {
        return {
          ...sale,
          splits: sale.splits.map(split => {
            if (split.brokerId === brokerId) {
              return {
                ...split,
                status: newStatus,
                paymentDate: newStatus === CommissionStatus.PAID ? new Date().toISOString().split('T')[0] : undefined,
                paymentMethod: newStatus === CommissionStatus.PAID ? 'PIX' : undefined
              };
            }
            return split;
          })
        };
      }
      return sale;
    }));
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch (activeView) {
      case 'dashboard':
        return <Dashboard sales={sales} currentUser={currentUser} />;
      case 'sales':
        return <Sales sales={sales} setSales={setSales} currentUser={currentUser} />;
      case 'commissions':
        return <Commissions sales={sales} currentUser={currentUser} onUpdateStatus={handleUpdateCommissionStatus} />;
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-center p-8 bg-white rounded-3xl border border-slate-100 shadow-sm">
            <div className="bg-blue-50 p-4 rounded-full mb-6">
              <HelpCircle size={48} className="text-blue-600" />
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Relatórios Customizados</h2>
            <p className="text-slate-500 max-w-md">O módulo de relatórios avançados está sendo preparado para integração com BI. Em breve você terá acesso a KPIs de performance e forecast de faturamento.</p>
          </div>
        );
      case 'team':
        return <Team team={team} setTeam={setTeam} currentUser={currentUser} />;
      default:
        return <Dashboard sales={sales} currentUser={currentUser} />;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
        <div className="w-full max-w-md">
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center p-3 bg-blue-600 rounded-2xl shadow-xl shadow-blue-200 mb-6">
              <LogIn className="text-white" size={32} />
            </div>
            <h1 className="text-3xl font-extrabold text-slate-800">ComissOne</h1>
            <p className="text-slate-500 mt-2">Gestão de Inteligência em Comissões</p>
          </div>

          <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-2xl shadow-slate-200/60">
            <div className="space-y-6">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <Key size={20} className="text-blue-500" /> Escolha seu Perfil
              </h2>
              <div className="grid grid-cols-1 gap-4">
                {team.map((user) => (
                  <button
                    key={user.id}
                    onClick={() => setCurrentUser(user)}
                    className="w-full group flex items-center justify-between p-5 bg-slate-50 border border-slate-100 rounded-2xl hover:border-blue-400 hover:bg-white hover:shadow-lg transition-all text-left"
                  >
                    <div>
                      <p className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors">{user.name}</p>
                      <p className="text-xs text-slate-400 font-medium uppercase tracking-wider">{user.role}</p>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 group-hover:bg-blue-600 group-hover:border-blue-600 transition-all">
                      <LogIn size={18} className="text-slate-400 group-hover:text-white transition-colors" />
                    </div>
                  </button>
                ))}
              </div>
              <div className="pt-6 border-t border-slate-100">
                <p className="text-xs text-center text-slate-400">
                  Ambiente de demonstração multi-tenant.<br/>
                  Dados isolados por agência.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentUser={currentUser} 
      activeView={activeView} 
      setActiveView={setActiveView}
      onLogout={() => {
        setCurrentUser(null);
        setActiveView('dashboard');
      }}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  Plus, 
  Edit, 
  Trash2, 
  UserPlus, 
  X, 
  Mail, 
  Shield, 
  User as UserIcon 
} from 'lucide-react';
import { User, UserRole } from '../types';

interface TeamProps {
  team: User[];
  setTeam: React.Dispatch<React.SetStateAction<User[]>>;
  currentUser: User;
}

const Team: React.FC<TeamProps> = ({ team, setTeam, currentUser }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [formData, setFormData] = useState<Partial<User>>({
    name: '',
    email: '',
    role: UserRole.BROKER
  });

  const openModal = (user?: User) => {
    if (user) {
      setEditingUser(user);
      setFormData(user);
    } else {
      setEditingUser(null);
      setFormData({
        name: '',
        email: '',
        role: UserRole.BROKER
      });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingUser(null);
  };

  const handleSave = () => {
    if (!formData.name || !formData.email) {
      alert("Por favor, preencha nome e e-mail.");
      return;
    }

    if (editingUser) {
      setTeam(prev => prev.map(u => u.id === editingUser.id ? { ...u, ...formData as User } : u));
    } else {
      const newUser: User = {
        id: `u-${Date.now()}`,
        name: formData.name!,
        email: formData.email!,
        role: formData.role as UserRole,
        agencyId: currentUser.agencyId
      };
      setTeam(prev => [...prev, newUser]);
    }
    closeModal();
  };

  const handleRemove = (id: string) => {
    if (id === currentUser.id) {
      alert("Você não pode remover a si mesmo.");
      return;
    }
    if (confirm("Tem certeza que deseja remover este membro da equipe?")) {
      setTeam(prev => prev.filter(u => u.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      {/* Header com Botão Adicionar */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-bold text-slate-800">Membros da Equipe</h3>
          <p className="text-sm text-slate-400">Gerencie os acessos e perfis da sua imobiliária.</p>
        </div>
        <button 
          onClick={() => openModal()}
          className="w-full sm:w-auto flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-bold transition-all shadow-lg shadow-blue-200"
        >
          <UserPlus size={20} /> Adicionar Membro
        </button>
      </div>

      {/* Grid de Membros */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {team.map(user => (
          <div key={user.id} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col transition-all hover:shadow-md group relative">
            {/* Ações Rápidas (Pencil / Trash) */}
            <div className="absolute top-4 right-4 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={() => openModal(user)}
                className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                title="Editar"
              >
                <Edit size={16} />
              </button>
              {user.id !== currentUser.id && (
                <button 
                  onClick={() => handleRemove(user.id)}
                  className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  title="Remover"
                >
                  <Trash2 size={16} />
                </button>
              )}
            </div>

            <div className="flex items-center gap-4 mb-4">
              <div className="w-14 h-14 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-bold text-xl border-2 border-white shadow-sm">
                {user.name.charAt(0)}
              </div>
              <div className="flex-1 min-w-0">
                <h4 className="font-bold text-slate-800 truncate">{user.name}</h4>
                <p className="text-xs text-slate-400 truncate flex items-center gap-1">
                  <Mail size={12} /> {user.email}
                </p>
              </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-slate-50">
              <span className={`text-[10px] px-2.5 py-1 rounded-lg font-black uppercase tracking-wider ${
                user.role === UserRole.ADMIN 
                  ? 'bg-indigo-50 text-indigo-600 border border-indigo-100' 
                  : 'bg-emerald-50 text-emerald-600 border border-emerald-100'
              }`}>
                {user.role}
              </span>
              <span className="text-[10px] font-bold text-slate-300">ID: {user.id.substring(0, 6)}</span>
            </div>
          </div>
        ))}
      </div>

      {/* Modal de Adição / Edição */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-[32px] shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-50 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-slate-800">{editingUser ? 'Editar Membro' : 'Novo Membro'}</h3>
                <p className="text-xs text-slate-400">Configure as informações do usuário.</p>
              </div>
              <button onClick={closeModal} className="bg-slate-50 p-2 rounded-full text-slate-400 hover:text-slate-600 transition-colors">
                <X size={20} />
              </button>
