import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Sales from './components/Sales';
import Commissions from './components/Commissions';
import Team from './components/Team';
import { User, Sale, UserRole, CommissionStatus } from './types';
import { MOCK_USERS, MOCK_SALES } from './constants';
import { LogIn, Key, HelpCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState('dashboard');
  const [sales, setSales] = useState<Sale[]>(MOCK_SALES);
  const [team, setTeam] = useState<User[]>(MOCK_USERS);

  // Persistence simulation
  useEffect(() => {
    const savedSales = localStorage.getItem('comissone_sales');
    if (savedSales) setSales(JSON.parse(savedSales));

    const savedTeam = localStorage.getItem('comissone_team');
    if (savedTeam) setTeam(JSON.parse(savedTeam));
  }, []);

  useEffect(() => {
    localStorage.setItem('comissone_sales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('comissone_team', JSON.stringify(team));
  }, [team]);

  const handleUpdateCommissionStatus = (saleId: string, brokerId: string, newStatus: CommissionStatus) => {
    setSales(prevSales => prevSales.map(sale => {
      if (sale.id === saleId) {
        return {
          ...sale,
          splits: sale.splits.map(split => {
            if (split.brokerId === brokerId) {
              return {
                ...split,
                status: newStatus,
                paymentDate: newStatus === CommissionStatus.PAID ? new Date().toISOString().split('T')[0] : undefined,
                paymentMethod: newStatus === CommissionStatus.PAID ? 'PIX' : undefined
              };
            }
            return split;
          })
        };
      }
      return sale;
    }));
  };

  const handleUpdateForecast = (saleId: string, brokerId: string, newForecastDate: string) => {
    setSales(prevSales => prevSales.map(sale => {
      if (sale.id === saleId) {
        return {
          ...sale,
          splits: sale.splits.map(split => {
            if (split.brokerId === brokerId) {
              return {
                ...split,
                forecastDate: newForecastDate
              };
            }
            return split;
          })
        };
      }
      return sale;
    }));
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch (activeView) {
      case 'dashboard':
        return <Dashboard sales={sales} currentUser={currentUser} />;
      case 'sales':
        return <Sales sales={sales} setSales={setSales} currentUser={currentUser} team={team} />;
      case 'commissions':
        return (
          <Commissions 
            sales={sales} 
            currentUser={currentUser} 
            onUpdateStatus={handleUpdateCommissionStatus}
            onUpdateForecast={handleUpdateForecast}
          />
        );
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center h-[60vh] text-center p-8 bg-white rounded-3xl border border-slate-100 shadow-sm">
            <div className="bg-blue-50 p-4 rounded-full mb-6">
              <HelpCircle size={48} className="text-blue-600" />
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Relatórios Customizados</h2>
            <p className="text-slate-500 max-w-md">O módulo de relatórios avançados está sendo preparado para integração com BI. Em breve você terá acesso a KPIs de performance e forecast de faturamento.</p>
          </div>
        );
      case 'team':
        return <Team team={team} setTeam={setTeam} currentUser={currentUser} />;
      default:
        return <Dashboard sales={sales} currentUser={currentUser} />;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
        <div className="w-full max-w-md">
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center p-3 bg-blue-600 rounded-2xl shadow-xl shadow-blue-200 mb-6">
              <LogIn className="text-white" size={32} />
            </div>
            <h1 className="text-3xl font-extrabold text-slate-800">ComissOne</h1>
            <p className="text-slate-500 mt-2">Gestão de Inteligência em Comissões</p>
          </div>

          <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-2xl shadow-slate-200/60">
            <div className="space-y-6">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <Key size={20} className="text-blue-500" /> Escolha seu Perfil
              </h2>
              <div className="grid grid-cols-1 gap-4">
                {team.map((user) => (
                  <button
                    key={user.id}
                    onClick={() => setCurrentUser(user)}
                    className="w-full group flex items-center justify-between p-5 bg-slate-50 border border-slate-100 rounded-2xl hover:border-blue-400 hover:bg-white hover:shadow-lg transition-all text-left"
                  >
                    <div>
                      <p className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors">{user.name}</p>
                      <p className="text-xs text-slate-400 font-medium uppercase tracking-wider">{user.role}</p>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 group-hover:bg-blue-600 group-hover:border-blue-600 transition-all">
                      <LogIn size={18} className="text-slate-400 group-hover:text-white transition-colors" />
                    </div>
                  </button>
                ))}
              </div>
              <div className="pt-6 border-t border-slate-100">
                <p className="text-xs text-center text-slate-400">
                  Ambiente de demonstração multi-tenant.<br/>
                  Dados isolados por agência.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentUser={currentUser} 
      activeView={activeView} 
      setActiveView={setActiveView}
      onLogout={() => {
        setCurrentUser(null);
        setActiveView('dashboard');
      }}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  Search, 
  Filter, 
  Download, 
  ArrowUpRight, 
  DollarSign, 
  Clock, 
  CheckCircle2, 
  AlertTriangle, 
  Wallet,
  Calendar,
  X,
  CalendarDays
} from 'lucide-react';
import { Sale, User, UserRole, CommissionStatus } from '../types';

interface CommissionsProps {
  sales: Sale[];
  currentUser: User;
  onUpdateStatus: (saleId: string, brokerId: string, newStatus: CommissionStatus) => void;
  onUpdateForecast?: (saleId: string, brokerId: string, newForecastDate: string) => void;
}

const Commissions: React.FC<CommissionsProps> = ({ sales, currentUser, onUpdateStatus, onUpdateForecast }) => {
  const [statusFilter, setStatusFilter] = useState<string>('ALL');
  const [searchTerm, setSearchTerm] = useState('');

  // Estados para modal de previsão
  const [isForecastModalOpen, setIsForecastModalOpen] = useState(false);
  const [selectedComm, setSelectedComm] = useState<{saleId: string, brokerId: string, property: string, forecastDate?: string} | null>(null);
  const [tempForecastDate, setTempForecastDate] = useState('');

  const isAdmin = currentUser.role === UserRole.ADMIN;

  const commissionList = useMemo(() => {
    const list: any[] = [];
    sales.forEach(sale => {
      sale.splits.forEach(split => {
        if (isAdmin || split.brokerId === currentUser.id) {
          list.push({
            saleId: sale.id,
            brokerId: split.brokerId,
            brokerName: split.brokerName,
            property: sale.propertyAddress,
            value: split.calculatedValue,
            status: split.status,
            date: sale.saleDate,
            paymentDate: split.paymentDate,
            paymentMethod: split.paymentMethod,
            forecastDate: split.forecastDate
          });
        }
      });
    });
    return list.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [sales, currentUser, isAdmin]);

  const filteredCommissions = commissionList.filter(c => {
    const matchesStatus = statusFilter === 'ALL' || c.status === statusFilter;
    const matchesSearch = c.property.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         c.brokerName.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  const getStatusBadge = (status: CommissionStatus) => {
    switch (status) {
      case CommissionStatus.PAID:
        return <span className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-emerald-100"><CheckCircle2 size={14} /> PAGO</span>;
      case CommissionStatus.PENDING:
        return <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-blue-100"><Clock size={14} /> PENDENTE</span>;
      case CommissionStatus.OVERDUE:
        return <span className="bg-red-50 text-red-600 px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1.5 border border-red-100"><AlertTriangle size={14} /> ATRASADO</span>;
    }
  };

  const handleOpenForecastModal = (comm: any) => {
    setSelectedComm({
      saleId: comm.saleId,
      brokerId: comm.brokerId,
      property: comm.property,
      forecastDate: comm.forecastDate
    });
    setTempForecastDate(comm.forecastDate || '');
    setIsForecastModalOpen(true);
  };

  const handleSaveForecast = () => {
    if (selectedComm && onUpdateForecast) {
      onUpdateForecast(selectedComm.saleId, selectedComm.brokerId, tempForecastDate);
      setIsForecastModalOpen(false);
      setSelectedComm(null);
    }
  };

  const handleExportCSV = () => {
    const headers = ["Data", "Imóvel", "Corretor", "Valor", "Status", "Previsão"];
    const rows = filteredCommissions.map(c => [
      c.date,
      c.property,
      c.brokerName,
      c.value.toString(),
      c.status,
      c.forecastDate || ""
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

