import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import Sales from './components/Sales';
import Commissions from './components/Commissions';
import Team from './components/Team';
import Reports from './components/Reports';
import { User, Sale, UserRole, CommissionStatus } from './types';
import { MOCK_USERS, MOCK_SALES } from './constants';
import { LogIn, Key } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState('dashboard');
  const [sales, setSales] = useState<Sale[]>(MOCK_SALES);
  const [team, setTeam] = useState<User[]>(MOCK_USERS);

  // Persistence simulation
  useEffect(() => {
    const savedSales = localStorage.getItem('comissone_sales');
    if (savedSales) setSales(JSON.parse(savedSales));

    const savedTeam = localStorage.getItem('comissone_team');
    if (savedTeam) setTeam(JSON.parse(savedTeam));
  }, []);

  useEffect(() => {
    localStorage.setItem('comissone_sales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('comissone_team', JSON.stringify(team));
  }, [team]);

  const handleUpdateCommissionStatus = (saleId: string, brokerId: string, newStatus: CommissionStatus) => {
    setSales(prevSales => prevSales.map(sale => {
      if (sale.id === saleId) {
        return {
          ...sale,
          splits: sale.splits.map(split => {
            if (split.brokerId === brokerId) {
              return {
                ...split,
                status: newStatus,
                paymentDate: newStatus === CommissionStatus.PAID ? new Date().toISOString().split('T')[0] : undefined,
                paymentMethod: newStatus === CommissionStatus.PAID ? 'PIX' : undefined
              };
            }
            return split;
          })
        };
      }
      return sale;
    }));
  };

  const handleUpdateForecast = (saleId: string, brokerId: string, newForecastDate: string) => {
    setSales(prevSales => prevSales.map(sale => {
      if (sale.id === saleId) {
        return {
          ...sale,
          splits: sale.splits.map(split => {
            if (split.brokerId === brokerId) {
              return {
                ...split,
                forecastDate: newForecastDate
              };
            }
            return split;
          })
        };
      }
      return sale;
    }));
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch (activeView) {
      case 'dashboard':
        return <Dashboard sales={sales} currentUser={currentUser} />;
      case 'sales':
        return <Sales sales={sales} setSales={setSales} currentUser={currentUser} team={team} />;
      case 'commissions':
        return (
          <Commissions 
            sales={sales} 
            currentUser={currentUser} 
            onUpdateStatus={handleUpdateCommissionStatus}
            onUpdateForecast={handleUpdateForecast}
          />
        );
      case 'reports':
        return <Reports sales={sales} team={team} currentUser={currentUser} />;
      case 'team':
        return <Team team={team} setTeam={setTeam} currentUser={currentUser} />;
      default:
        return <Dashboard sales={sales} currentUser={currentUser} />;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
        <div className="w-full max-w-md">
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center p-3 bg-blue-600 rounded-2xl shadow-xl shadow-blue-200 mb-6">
              <LogIn className="text-white" size={32} />
            </div>
            <h1 className="text-3xl font-extrabold text-slate-800">ComissOne</h1>
            <p className="text-slate-500 mt-2">Gestão de Inteligência em Comissões</p>
          </div>

          <div className="bg-white p-8 rounded-[32px] border border-slate-100 shadow-2xl shadow-slate-200/60">
            <div className="space-y-6">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <Key size={20} className="text-blue-500" /> Escolha seu Perfil
              </h2>
              <div className="grid grid-cols-1 gap-4">
                {team.map((user) => (
                  <button
                    key={user.id}
                    onClick={() => setCurrentUser(user)}
                    className="w-full group flex items-center justify-between p-5 bg-slate-50 border border-slate-100 rounded-2xl hover:border-blue-400 hover:bg-white hover:shadow-lg transition-all text-left"
                  >
                    <div>
                      <p className="font-bold text-slate-800 group-hover:text-blue-600 transition-colors">{user.name}</p>
                      <p className="text-xs text-slate-400 font-medium uppercase tracking-wider">{user.role}</p>
                    </div>
                    <div className="bg-white p-2 rounded-xl border border-slate-100 group-hover:bg-blue-600 group-hover:border-blue-600 transition-all">
                      <LogIn size={18} className="text-slate-400 group-hover:text-white transition-colors" />
                    </div>
                  </button>
                ))}
              </div>
              <div className="pt-6 border-t border-slate-100">
                <p className="text-xs text-center text-slate-400">
                  Ambiente de demonstração multi-tenant.<br/>
                  Dados isolados por agência.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      currentUser={currentUser} 
      activeView={activeView} 
      setActiveView={setActiveView}
      onLogout={() => {
        setCurrentUser(null);
        setActiveView('dashboard');
      }}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { 
  BarChart, 
  Bar, 
